/**
 * Fixed LMDB workload for the native execution kernels introduced together: batch filter/project, primitive hash join,
 * composite grouping, packed top-K, and lazy public results. Feature properties can be toggled with JMH JVM arguments
 * to compare each kernel with its retained fallback. Every invocation validates its row count or digest.
 */
@State(Scope.Benchmark)
@Warmup(iterations = 3, time = 1, timeUnit = TimeUnit.SECONDS)
@BenchmarkMode(Mode.AverageTime)
@Fork(value = 1, jvmArgs = { "-Xms1G", "-Xmx3G" })
@Measurement(iterations = 4, time = 1, timeUnit = TimeUnit.SECONDS)
@OutputTimeUnit(TimeUnit.MILLISECONDS)
public class NativeExecutionKernelBenchmark {

	private static final String EX = "http://example.com/";
	private static final int ITEMS = 20_000;

	@Param({
			"scanFilterProject",
			"primitiveHashJoin",
			"groupByTwoKeys",
			"sortTopK",
			"consumeIdsOnly",
			"consumeValues"
	})
	public String variant;

	private java.io.File dataDir;
	private SailRepository repository;
	private String query;
	private long expected;

	@Setup(Level.Trial)
	public void setUp() {
		dataDir = Files.newTemporaryFolder();
		repository = new SailRepository(new LmdbStore(dataDir, new LmdbStoreConfig("spoc,posc,ospc")));
		try (SailRepositoryConnection connection = repository.getConnection()) {
			ValueFactory vf = connection.getValueFactory();
			IRI type = vf.createIRI(EX, "type");
			IRI item = vf.createIRI(EX, "Item");
			IRI score = vf.createIRI(EX, "score");
			IRI bucket = vf.createIRI(EX, "bucket");
			IRI category = vf.createIRI(EX, "category");
			connection.begin();
			for (int i = 0; i < ITEMS; i++) {
				IRI subject = vf.createIRI(EX, "item" + i);
				connection.add(subject, type, item);
				connection.add(subject, score, vf.createLiteral(i % 1_000));
				connection.add(subject, bucket, vf.createIRI(EX, "bucket" + (i % 128)));
				connection.add(subject, category, vf.createIRI(EX, "category" + (i % 16)));
			}
			connection.commit();
		}

		switch (variant) {
		case "scanFilterProject":
			query = select("?s ?score", "?s ex:score ?score . FILTER(?score >= 500)", "");
			expected = ITEMS / 2L;
			break;
		case "primitiveHashJoin":
		case "consumeIdsOnly":
		case "consumeValues":
			query = select("?s ?score", "?s ex:type ex:Item ; ex:score ?score", "");
			expected = ITEMS;
			break;
		case "groupByTwoKeys":
			query = select("?bucket ?category (COUNT(?s) AS ?count)",
					"?s ex:bucket ?bucket ; ex:category ?category", " GROUP BY ?bucket ?category");
			expected = ITEMS;
			break;
		case "sortTopK":
			query = select("?s ?score", "?s ex:type ex:Item ; ex:score ?score", " ORDER BY DESC(?score) ?s LIMIT 100");
			expected = 100L;
			break;
		default:
			throw new IllegalArgumentException(variant);
		}
	}

	private static String select(String projection, String body, String suffix) {
		return "PREFIX ex: <" + EX + "> SELECT " + projection + " WHERE { " + body + " }" + suffix;
	}

	@TearDown(Level.Trial)
	public void tearDown() throws IOException {
		repository.shutDown();
		FileUtil.deleteDir(dataDir);
	}

	@Benchmark
	public long executeQuery() {
		try (SailRepositoryConnection connection = repository.getConnection();
				TupleQueryResult result = connection.prepareTupleQuery(query).evaluate()) {
			long rows = 0L;
			long digest = 0L;
			while (result.hasNext()) {
				BindingSet bindings = result.next();
				rows++;
				if ("consumeValues".equals(variant)) {
					digest += ((Literal) bindings.getValue("score")).longValue();
				} else if ("groupByTwoKeys".equals(variant)) {
					digest += ((Literal) bindings.getValue("count")).longValue();
				}
			}
			long actual = "groupByTwoKeys".equals(variant) ? digest : rows;
			if (actual != expected) {
				throw new IllegalStateException(variant + ": expected " + expected + " but got " + actual);
			}
			return rows ^ digest;
		}
	}
}
